// 将表格中"同上"替换为上方单元格值，"同左"替换为左侧单元格值
var doc = Application.ActiveDocument;
var tables = doc.Tables;
var result = { total: 0, replaced: 0 };

for (var t = 0; t < tables.Count; t++) {
    var table = tables.Item(t);
    for (var row = 1; row < table.Rows.Count + 1; row++) {
        for (var col = 1; col < table.Columns.Count + 1; col++) {
            var cell = table.Cell(row, col).Range;
            var text = cell.Text.replace(/\r\n/g, '').trim();

            if (text === '同上' && row > 1) {
                var aboveCell = table.Cell(row - 1, col).Range;
                var aboveText = aboveCell.Text.replace(/\r\n/g, '').trim();
                if (aboveText) {
                    cell.Text = aboveText;
                    result.replaced++;
                }
            } else if (text === '同左' && col > 1) {
                var leftCell = table.Cell(row, col - 1).Range;
                var leftText = leftCell.Text.replace(/\r\n/g, '').trim();
                if (leftText) {
                    cell.Text = leftText;
                    result.replaced++;
                }
            }
            result.total++;
        }
    }
}

return result;

